    for i, num := range nums {
        pos[num] = append(pos[num], int64(i))
    }

    // For each query
    for i, query := range queries {
        l, r, threshold := query[0], query[1], query[2]
        freq := make(map[int64]int64)

        // Count frequency of each number in the subarray nums[l...r]
        for j := l; j <= r; j++ {
            num := nums[j]
            freq[num]++
        }

        // Find the number with frequency >= threshold
        maxFreq := int64(-1)
